/// MAIN-PARA
fn p_main_para(state: &mut ProgramState) {
    state.ws_switches.ws_err_flg = "N".into();
    state.ws_switches.ws_auths_eof = "N".into();
    state.carddemo_commarea.cdemo_cpvs_info.cdemo_cpvs_next_page_flg = "N".into();
    state.ws_switches.ws_send_erase_flg = "Y".into();
    state.ws_variables.ws_message = FixedString::spaces();
    state.copau0ao.errmsgo = FixedString::spaces();
    state.copau0ai.acctidl = -1 as i32;
    // SKIP: unresolved condition
    p_receive_paulst_screen(state);
    match state._unresolved_eibaid {
        _ => {
            p_process_enter_key(state);
            if state.ws_variables.ws_acct_id.trimmed() == "\0" {
                state.copau0ao.acctido = FixedString::spaces();
            } else {
                state.copau0ao.acctido = FixedString::copy_from(&state.ws_variables.ws_acct_id);
            }
            p_send_paulst_screen(state);
        }
        _ => {
            state.carddemo_commarea.cdemo_general_info.cdemo_to_program = FixedString::copy_from(&state.ws_variables.ws_pgm_menu);
            p_return_to_prev_screen(state);
            p_send_paulst_screen(state);
        }
        _ => {
            p_process_pf7_key(state);
            p_send_paulst_screen(state);
        }
        _ => {
            p_process_pf8_key(state);
            p_send_paulst_screen(state);
        }
        _ => {
            state.ws_switches.ws_err_flg = "Y".into();
            state.copau0ai.acctidl = -1 as i32;
            state.ws_variables.ws_message = FixedString::copy_from(&state.ccda_common_messages.ccda_msg_invalid_key);
            p_send_paulst_screen(state);
        }
    }
    // EXEC CICS RETURN 
    state.cics.execute("RETURN", &[("TRANSID", Some("_unknown")), ("WS-CICS-TRANID", Some("_unknown")), ("COMMAREA", Some("_unknown")), ("CARDDEMO-COMMAREA", Some("_unknown"))]);
}

