/// PROCESS-PF7-KEY
fn p_process_pf7_key(state: &mut ProgramState) {
    if state.carddemo_commarea.cdemo_cpvs_info.cdemo_cpvs_page_num > 1 {
        state.carddemo_commarea.cdemo_cpvs_info.cdemo_cpvs_page_num = (state.carddemo_commarea.cdemo_cpvs_info.cdemo_cpvs_page_num as i64 - 1 as i64) as i32;
        state.ws_variables.ws_auth_key_save = FixedString::copy_from(&state.carddemo_commarea.cdemo_cpvs_info.cdemo_cpvs_paukey_prev_pg[((state.carddemo_commarea.cdemo_cpvs_info.cdemo_cpvs_page_num - 1) as usize).min(19)]);
        p_get_auth_summary(state);
        state.ws_switches.ws_send_erase_flg = "N".into();
        state.carddemo_commarea.cdemo_cpvs_info.cdemo_cpvs_next_page_flg = "Y".into();
        state.copau0ai.acctidl = -1 as i32;
        p_initialize_auth_data(state);
        p_process_page_forward(state);
    } else {
        state.ws_variables.ws_message = "You are already at the top of the page...".into();
        state.ws_switches.ws_send_erase_flg = "N".into();
    }
}

